// Calculate last Mon-Sun week range
const now = new Date();
const day = now.getUTCDay();
const daysToLastMonday = day === 0 ? 6 : (day - 1) + 7;
const lastMonday = new Date(now);
lastMonday.setUTCDate(now.getUTCDate() - daysToLastMonday);
lastMonday.setUTCHours(0, 0, 0, 0);

const lastSunday = new Date(lastMonday);
lastSunday.setUTCDate(lastMonday.getUTCDate() + 6);
lastSunday.setUTCHours(23, 59, 59, 999);

const fmt = (d) => d.toISOString();
const fmtDate = (d) => d.toISOString().split('T')[0];

return [{ json: {
  weekStart: fmt(lastMonday),
  weekEnd: fmt(lastSunday),
  weekLabel: fmtDate(lastMonday) + ' to ' + fmtDate(lastSunday),
  reportDate: fmtDate(now)
} }];

// Build A/B test report from all fetched data
const dates = $('Calculate Week Range').first().json;

const testsRaw = $('Fetch A/B Tests').first().json.body || [];
const sendsRaw = $('Fetch This Week Sends').first().json.body || [];
const winnersRaw = $('Fetch Winners This Week').first().json.body || [];

const tests = Array.isArray(testsRaw) ? testsRaw : [];
const sends = Array.isArray(sendsRaw) ? sendsRaw : [];
const winners = Array.isArray(winnersRaw) ? winnersRaw : [];

const activeTests = tests.filter(t => t.status === 'active');
const completedTests = tests.filter(t => t.status === 'completed');

// === Sends by test + variant ===
const sendsByTest = {};
for (const s of sends) {
  const key = s.test_id;
  if (!sendsByTest[key]) sendsByTest[key] = { a: { total: 0, converted: 0 }, b: { total: 0, converted: 0 } };
  const variant = (s.variant || 'a').toLowerCase();
  const bucket = variant === 'b' ? 'b' : 'a';
  sendsByTest[key][bucket].total += 1;
  if (s.converted) sendsByTest[key][bucket].converted += 1;
}

// === Build test results table ===
const testResults = tests.map(t => {
  const sd = sendsByTest[t.id] || { a: { total: 0, converted: 0 }, b: { total: 0, converted: 0 } };
  const aRate = sd.a.total > 0 ? Math.round((sd.a.converted / sd.a.total) * 10000) / 100 : 0;
  const bRate = sd.b.total > 0 ? Math.round((sd.b.converted / sd.b.total) * 10000) / 100 : 0;
  const totalSends = sd.a.total + sd.b.total;
  const totalConverted = sd.a.converted + sd.b.converted;
  return {
    testName: t.test_name || 'Unnamed',
    channel: t.channel || '-',
    status: t.status,
    variantA: t.variant_a || 'A',
    variantB: t.variant_b || 'B',
    aRate,
    bRate,
    aSends: sd.a.total,
    bSends: sd.b.total,
    totalSends,
    totalConverted,
    winner: t.winner || '-',
    metric: t.metric_target || '-'
  };
});

// === Overall metrics ===
const totalSendsWeek = sends.length;
const totalConvertedWeek = sends.filter(s => s.converted).length;
const avgConversion = totalSendsWeek > 0 ? Math.round((totalConvertedWeek / totalSendsWeek) * 10000) / 100 : 0;

// === Highlights ===
const highlights = [];
for (const w of winners) {
  highlights.push('Winner declared: "' + (w.test_name || 'Test') + '" (' + w.channel + ') - Variant ' + (w.winner || '?') + ' wins');
}
if (activeTests.length > 0) highlights.push(activeTests.length + ' test(s) still running and collecting data');
if (totalSendsWeek > 0) highlights.push(totalSendsWeek + ' total sends this week with ' + avgConversion + '% avg conversion');
if (tests.length === 0) highlights.push('No active or completed A/B tests found. Consider seeding new tests via TG-105.');

// === Actions ===
const actions = [];
if (activeTests.length === 0 && completedTests.length === 0) {
  actions.push('No A/B tests running - seed new SMS and email tests via TG-105 router');
  actions.push('Start with follow-up message variants or quote email subject lines');
} else {
  if (winners.length > 0) actions.push('Apply winning variants to production templates');
  const lowSampleTests = testResults.filter(t => t.status === 'active' && t.totalSends < 20);
  if (lowSampleTests.length > 0) actions.push(lowSampleTests.length + ' test(s) have low sample size (<20 sends) - continue collecting data');
  if (activeTests.length < 2) actions.push('Consider adding more tests - optimal is 2-3 concurrent A/B tests');
}
if (actions.length === 0) actions.push('A/B testing program on track - no action needed');

// === Build TG-118 compatible report ===
const noTests = tests.length === 0;

const sections = [
  {
    type: 'metrics',
    title: 'A/B Testing Overview',
    items: [
      { label: 'Active Tests', value: activeTests.length.toString(), change: '' },
      { label: 'Sends This Week', value: totalSendsWeek.toString(), change: '' },
      { label: 'Winners Declared', value: winners.length.toString(), change: '' },
      { label: 'Avg Conversion', value: avgConversion + '%', change: '' }
    ]
  }
];

if (testResults.length > 0) {
  sections.push({
    type: 'table',
    title: 'Test Results by Variant',
    headers: ['Test', 'Channel', 'Status', 'A Rate', 'B Rate', 'Sends', 'Winner'],
    rows: testResults.map(t => [
      t.testName,
      t.channel,
      t.status,
      t.aRate + '%',
      t.bRate + '%',
      t.totalSends.toString(),
      t.winner
    ])
  });
}

sections.push({
  type: 'highlights',
  title: noTests ? 'No Active Tests' : 'Key Highlights',
  items: highlights
});

sections.push({
  type: 'actions',
  title: 'Recommended Actions',
  items: actions
});

const reportData = {
  report_title: 'Weekly A/B Test Report',
  report_subtitle: dates.weekLabel,
  sections
};

const subject = noTests
  ? 'TG A/B Tests: No active tests - time to seed new experiments'
  : 'TG A/B Tests: ' + activeTests.length + ' active, ' + winners.length + ' winners, ' + avgConversion + '% avg conversion';

return [{ json: {
  reportData,
  subject,
  storePayload: {
    report_type: 'ab_test_results',
    report_date: dates.reportDate,
    report_data: {
      week_label: dates.weekLabel,
      active_tests: activeTests.length,
      completed_tests: completedTests.length,
      winners_this_week: winners.length,
      total_sends: totalSendsWeek,
      avg_conversion: avgConversion,
      test_results: testResults,
      highlights,
      actions
    }
  }
} }];

// Log completion
const data = $('Build Report Data').first().json;
return [{ json: {
  status: 'complete',
  report_type: 'ab_test_results',
  report_date: data.storePayload.report_date,
  active_tests: data.storePayload.report_data.active_tests,
  winners_this_week: data.storePayload.report_data.winners_this_week,
  completedAt: new Date().toISOString()
} }];
